const fmtPrice=t=>{const n=Number(String(t||"").replace(/[^\d.]/g,""));return n?"₾"+n.toLocaleString("en-US"):""};document.addEventListener("DOMContentLoaded",async()=>{const t=document.getElementById("galleryGrid");if(t){if(!window.sanityImgUrl||!window.fetchAllArtworks)return console.error("❌ sanity-client.js not loaded — gallery.js requires it"),void(t.innerHTML="<p class='muted'>Failed to load artworks.</p>");window.nvSkeleton?window.nvSkeleton(t,8):t.innerHTML="<p class='muted'>Loading artworks…</p>";try{const e=await window.fetchAllArtworks();if(!e||!e.length)return void(window.nvEmpty?window.nvEmpty(t,"No artworks available"):t.innerHTML="<p class='muted'>No artworks found.</p>");t.innerHTML="";const a=e.slice().sort((t,n)=>{const e="sold"===(t.status||"").toLowerCase().trim();return e!==("sold"===(n.status||"").toLowerCase().trim())?e?1:-1:"number"==typeof t.order&&"number"==typeof n.order?t.order-n.order:t._createdAt&&n._createdAt?new Date(n._createdAt)-new Date(t._createdAt):0});a.forEach(n=>{const e="sold"===(n.status||"").toLowerCase().trim(),a=document.createElement("article");a.className="card",a.innerHTML=`\n        <div class="nv-img-wrap"${n.lqip?` style="background-image:url(${n.lqip})"`:""}>\n          <img class="thumb-img nv-lqip"\n            src="${window.sanityImgUrl(n.img,{w:600,q:80})}"\n            srcset="${window.sanitySrcset(n.img,[400,600,800])}"\n            sizes="(max-width: 600px) 100vw, (max-width: 900px) 50vw, 400px"\n            alt="${n.title}"\n            loading="lazy"\n            decoding="async"\n            width="600" height="450"\n            onload="this.classList.add('nv-loaded');this.parentNode.style.backgroundImage=''"\n            onerror="this.classList.add('nv-loaded');this.parentNode.style.backgroundImage='';this.src='./images/placeholder.jpg'" />\n        </div>\n\n        <div class="card-body">\n          <h3>${n.title}</h3>\n\n          ${n.artist&&n.artist.slug?`<a class="artist-credit" href="./artists/artist.html?artist=${n.artist.slug}" aria-label="View artworks by ${n.artist.name||"artist"}">${n.artist.name}</a>`:""}\n\n          <p class="muted">\n            ${n.medium||""}${n.size?" | "+n.size:""}\n          </p>\n\n          <div class="card-row">\n            <span class="price">${fmtPrice(n.price)}</span>\n\n            <div class="buy-row">\n              ${e?'<span class="sold-badge">SOLD</span>':`\n                    <a class="buy insta"\n                      href="https://instagram.com/ninart.vision"\n                      target="_blank">Instagram</a>\n\n                    <a class="buy"\n                      href="https://wa.me/995579388833?text=Hello, I'm interested in ${encodeURIComponent(n.title)}"\n                      target="_blank">WhatsApp</a>\n                  `}\n            </div>\n          </div>\n        </div>\n      `,t.appendChild(a)});var n=a.find(function(t){return"sold"!==(t.status||"").toLowerCase()})||a[0];n&&"function"==typeof window.injectSchema&&window.injectSchema("artwork",n)}catch(n){console.error(n),window.nvError?window.nvError(t,"Could not load artworks. Please try again.",function(){location.reload()}):t.innerHTML="<p class='muted'>Failed to load artworks.</p>"}}else console.error("❌ galleryGrid not found")});